input.command:
kubectl patch statefulset mongodb-replica -n mongodb --type='json' -p='[
  {"op":"replace","path":"/spec/template/spec/containers/0/readinessProbe","value":{"exec":{"command":["/usr/local/bin/probe.sh"]},"initialDelaySeconds":20,"periodSeconds":15,"timeoutSeconds":10,"failureThreshold":5,"successThreshold":1}},
  {"op":"replace","path":"/spec/template/spec/containers/0/livenessProbe","value":{"exec":{"command":["/usr/local/bin/probe.sh"]},"initialDelaySeconds":60,"periodSeconds":20,"timeoutSeconds":10,"failureThreshold":6,"successThreshold":1}}
]'
kubectl delete pod -n mongodb mongodb-replica-0 mongodb-replica-1 mongodb-replica-2 --wait=false
